--
-- Table structure for table `yzz_yuebao_record`
--

DROP TABLE IF EXISTS `yzz_yuebao_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `yzz_yuebao_record` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID bản ghi',
  `order_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'Mã đơn hàng',
  `uid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'ID người dùng',
  `username` varchar(32) NOT NULL DEFAULT '' COMMENT 'Tên đăng nhập',
  `type` varchar(20) NOT NULL DEFAULT '' COMMENT 'Loại: deposit-nạp vào, withdraw-rút ra, income-thu nhập',
  `product_id` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'ID sản phẩm',
  `product_name` varchar(64) NOT NULL DEFAULT '' COMMENT 'Tên sản phẩm',
  `amount` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số tiền giao dịch',
  `before_balance` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư ví trước thao tác',
  `after_balance` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư ví sau thao tác',
  `before_yebao` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư tiết kiệm trước thao tác',
  `after_yebao` decimal(14,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư tiết kiệm sau thao tác',
  `status` varchar(20) NOT NULL DEFAULT 'success' COMMENT 'Trạng thái: success-thành công, pending-đang xử lý, failed-thất bại',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT 'Ghi chú',
  `ip` varchar(64) NOT NULL DEFAULT '' COMMENT 'Địa chỉ IP',
  `create_time` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Thời gian tạo',
  `update_time` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Thời gian cập nhật',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_order_id` (`order_id`),
  KEY `idx_uid` (`uid`),
  KEY `idx_type` (`type`),
  KEY `idx_status` (`status`),
  KEY `idx_create_time` (`create_time`),
  KEY `idx_uid_type` (`uid`,`type`),
  KEY `idx_uid_create_time` (`uid`,`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COMMENT='Bảng lịch sử giao dịch tiết kiệm';
/*!40101 SET character_set_client = @saved_cs_client */;

